    exec_result = conn->execute(sql_create_index_category);
    if (!exec_result) {
      return false;
    }

    // 4. Create unique index on sku with IF NOT EXISTS
    // Note: The reference materials show create_index returns non-unique by default
    // For unique index, we need to use the appropriate sqlgen mechanism
    // Based on the CreateIndex structure, we can set unique_ = true
    auto create_index_sku = sqlgen::create_index<"idx_product_sku", Product>("sku"_c);
    create_index_sku.unique_ = true;  // Set unique flag
    create_index_sku.if_not_exists_ = true;  // Apply IF NOT EXISTS
