namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // Begin transaction
  auto begin_result = conn | sqlgen::begin_transaction;
  if (!begin_result) {
    return false;
  }

  try {
    // Read from_account balance to verify sufficient funds
    auto from_account = (sqlgen::read<std::vector<Account>> 
                         | sqlgen::where("account_id"_c == from_account_id))(conn);

    if (!from_account || from_account->balance < amount) {
      conn | sqlgen::rollback;
      return false;
    }

    // Update from_account: deduct amount with balance check
    auto update_from = sqlgen::update<Account>("balance"_c.set("balance"_c - amount))
                     | sqlgen::where("account_id"_c == from_account_id && "balance"_c >= amount);
    auto update_from_result = update_from(conn);
    if (!update_from_result) {
      conn | sqlgen::rollback;
      return false;
    }

    // Update to_account: add amount
    auto update_to = sqlgen::update<Account>("balance"_c.set("balance"_c + amount))
                   | sqlgen::where("account_id"_c == to_account_id);
    auto update_to_result = update_to(conn);
    if (!update_to_result) {
      conn | sqlgen::rollback;
      return false;
    }

    // Commit transaction if all operations succeed
    auto commit_result = conn | sqlgen::commit;
    if (!commit_result) {
      conn | sqlgen::rollback;
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    conn | sqlgen::rollback;
    return false;
  }
}

}  // namespace transaction_transfer_funds
