    if (!drop_result) {
        return false;
    }

    // 3. Write the batch of items
    auto write_result = write(conn, items);
    if (!write_result) {
        return false;
    }

    // 4. Read items with quantity > 50, ordered by quantity descending
    auto read_result = (read<std::vector<Inventory>> 
                       | where("quantity"_c > 50) 
                       | order_by("quantity"_c.desc()))(conn);

    if (!read_result) {
