  if (!conn) {
    return false;
  }

  // Drop tables if they exist
  auto drop_parent = sqlgen::drop<Parent> | sqlgen::if_exists;
  auto drop_child = sqlgen::drop<Child> | sqlgen::if_exists;

  auto conn_after_drop = drop_parent(conn.value());
  if (!conn_after_drop) {
    return false;
  }
  conn_after_drop = drop_child(conn_after_drop.value());
  if (!conn_after_drop) {
    return false;
  }

  // Create tables
  auto create_parent = sqlgen::create_table<Parent>;
  auto create_child = sqlgen::create_table<Child>;

  auto conn_after_create = create_parent(conn_after_drop.value());
  if (!conn_after_create) {
    return false;
  }
  conn_after_create = create_child(conn_after_create.value());
  if (!conn_after_create) {
    return false;
  }

  // Insert parent and child records
  Parent parent{1, "Parent Record"};
  Child child{2, 1, "Child Record"};

  auto conn_after_insert = sqlgen::insert(parent)(conn_after_create.value());
  if (!conn_after_insert) {
    return false;
  }
  conn_after_insert = sqlgen::insert(child)(conn_after_insert.value());
  if (!conn_after_insert) {
